body.script:
//
// 1. Target your exact jsDelivr HTML file 
const url = "https://cdn.jsdelivr.net/gh/pradeepban-arch/Bit-Planes@main/index.html"; 

// 2. Define the cursor CSS we want to inject inside the running code 
const cursorStyles = ` <style> html, body, a, button, select, input { cursor: url('https://cdn.jsdelivr.net/gh/pradeepban-arch/cursors@main/bruh.png') 16 16, pointer !important; } </style> `; 

fetch(url) 
  .then(response => response.text()) 
  .then(htmlCode => { 
    // 3. Inject the CSS right before the closing </head> tag of the fetched file 
    const modifiedHtml = htmlCode.replace('</head>', cursorStyles + '</head>'); 
    // 4. Force the iframe to run the modified code 
    document.getElementById('app-frame').srcdoc = modifiedHtml; 
  }) 
  .catch(err => console.error("Error loading HTML file:", err));
//
